'use strict';

class URLHelper {
    /**
     * Gets url
     */
    static getUrl() {
        return window.location.pathname + window.location.search;
    }
    /**
     * Creates a url object by the fullpath.
     *
     * @param fullpath
     */
    static setUrl(fullpath) {
        if (fullpath) {
            let [pathname, search] = fullpath.split("?");
            if (!search)
                search = "";
            const params = pathname.split("/");
            const querySplit = search.split("&");
            let query = {};
            querySplit.forEach(item => {
                const [key, value] = item.split("=");
                query[key] = value;
            });
            return {
                pathname,
                search,
                fullpath,
                params,
                query
            };
        }
        return null;
    }
    /**
     * Checks the path it if matches in the url
     *
     * @param url
     * @param path
     * @param exact
     */
    static checkPathIfMatches(url, path, exact) {
        if (url) {
            if (path == "/")
                return exact ? url == "/" : true;
            else if (!exact)
                path = path.replace(/(\/)([^\/]+)/g, "($1$2)?");
            return url.match(new RegExp(`^${path}$`)) ? true : false;
        }
        return false;
    }
}

exports.URLHelper = URLHelper;
